#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_K 1005

// Define the structure for a tree node
typedef struct Node {
    int manager;
    int salary;
    struct Node* children[MAX_N];
    int numChildren;
} Node;

// Function to create a new tree node
Node* createNode(int manager, int salary) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->manager = manager;
    newNode->salary = salary;
    newNode->numChildren = 0;
    return newNode;
}

// Function to add a child to a node
void addChild(Node* parent, Node* child) {
    parent->children[parent->numChildren++] = child;
}

// Function to calculate the maximum amount of money that can be earned by robbing i employees under a node
int dfs(Node* node, int i, int** dp) {
    if (i == 0) return 0;
    if (dp[node->manager][i] != -1) return dp[node->manager][i];
    int maxAmount = 0;
    for (int j = 0; j <= i; j++) {
        int amount = 0;
        for (int k = 0; k < node->numChildren; k++) {
            amount += dfs(node->children[k], j, dp);
        }
        if (j > 0) amount += node->salary;
        maxAmount = (maxAmount > amount) ? maxAmount : amount;
    }
    dp[node->manager][i] = maxAmount;
    return maxAmount;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        Node* nodes[N];
        for (int i = 0; i < N; i++) {
            int manager, salary;
            scanf("%d %d", &manager, &salary);
            nodes[i] = createNode(manager, salary);
        }
        for (int i = 0; i < N; i++) {
            if (nodes[i]->manager != 0) {
                addChild(nodes[nodes[i]->manager - 1], nodes[i]);
            }
        }
        int** dp = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            dp[i] = (int*)malloc((K + 1) * sizeof(int));
            for (int j = 0; j <= K; j++) {
                dp[i][j] = -1;
            }
        }
        int maxAmount = dfs(nodes[0], K, dp);
        printf("%d\n", maxAmount);
        for (int i = 0; i < N; i++) {
            free(dp[i]);
        }
        free(dp);
    }
    return 0;
}

